class Solution {
    public String countOfAtoms(String formula) {
        Deque<Map<String, Integer>> stack = new ArrayDeque<>();
        stack.push(new HashMap<>());
        int n = formula.length();
        int i = 0;
        while (i < n) {
            if (formula.charAt(i) == '(') {
                stack.push(new HashMap<>());
                i++;
            } else if (formula.charAt(i) == ')') {
                Map<String, Integer> top = stack.pop();
                Map<String, Integer> prev = stack.peek();
                i++;
                int num = 1;
                if (i < n && Character.isDigit(formula.charAt(i))) {
                    num = 0;
                    while (i < n && Character.isDigit(formula.charAt(i))) {
                        num = num * 10 + (formula.charAt(i) - '0');
                        i++;
                    }
                }
                for (String key : top.keySet()) {
                    prev.put(key, prev.getOrDefault(key, 0) + top.get(key) * num);
                }
            } else {
                int j = i;
                j++;
                while (j < n && Character.isLowerCase(formula.charAt(j))) j++;
                String name = formula.substring(i, j);
                i = j;
                int num = 1;
                if (i < n && Character.isDigit(formula.charAt(i))) {
                    num = 0;
                    while (i < n && Character.isDigit(formula.charAt(i))) {
                        num = num * 10 + (formula.charAt(i) - '0');
                        i++;
                    }
                }
                Map<String, Integer> cur = stack.peek();
                cur.put(name, cur.getOrDefault(name, 0) + num);
            }
        }
        Map<String, Integer> counts = stack.pop();
        List<String> names = new ArrayList<>(counts.keySet());
        Collections.sort(names);
        StringBuilder sb = new StringBuilder();
        for (String name : names) {
            sb.append(name);
            int cnt = counts.get(name);
            if (cnt > 1) sb.append(cnt);
        }
        return sb.toString();
    }
}
